+    } else {
+      r.try_emplace("name", k);
+    }
+    r.try_emplace("arrow", v.arrow.as_record());
+    r.try_emplace("cpp", v.cpp.as_record());
+    r.try_emplace("c", v.c.as_record());
+  }
+  return result;
+}
