+  request.SetBucket(bucket);
+  request.SetKey(key);
+  auto outcome = client.DeleteObject(request);
+  if (not outcome.IsSuccess()) {
+    const auto& error = outcome.GetError();
+    return arrow::Status::IOError("failed to delete S3 object: ",
