+  if (auto file = std::ifstream{"/sys/devices/virtual/dmi/id/sys_vendor"}) {
+    auto line = std::string{};
+    if (std::getline(file, line)) {
+      if (line.find("Amazon") != std::string::npos) {
+        return true;
+      }
+    }
+  }
+#endif
+  return false;
+}
